function _sendMessage(
    bytes32 id,
    bytes memory recipient,
    bytes memory payload,
    address sender,
    uint256 totalValue,
    uint256 recipientValue,
    uint256 gasLimit,
    address refundRecipient
) private {
    uint16 targetChain = getWormholeChain(recipient);
    address targetAddress = getRemoteGateway(recipient);
    _wormholeRelayer.sendPayloadToEvm{value: totalValue}(
        targetChain,
        targetAddress,
        abi.encode(id, InteroperableAddress.formatEvmV1(block.chainid, sender), recipient, payload),
        recipientValue,
        gasLimit,
        targetChain,
        refundRecipient
    );
}

function scheduleBatch(
    address[] calldata targets,
    uint256[] calldata values,
    bytes[] calldata payloads,
    bytes32 predecessor,
    bytes32 salt,
    uint256 delay
) public virtual override {
    super.scheduleBatch(targets, values, payloads, predecessor, salt, delay);
    bytes32 id = hashOperationBatch(targets, values, payloads, predecessor, salt);
    _operationsBatchIdSet.add(id);
    _operationsBatchMap[id] = OperationBatch({
        targets: targets,
        values: values,
        payloads: payloads,
        predecessor: predecessor,
        salt: salt,
        delay: delay
    });
}

function _refund(
    IERC20 token,
    uint256 tokenPrice,
    uint256 actualGasCost,
    uint256 actualUserOpFeePerGas,
    address prefunder,
    uint256 prefundAmount,
    bytes calldata prefundContext
) internal virtual override(PaymasterERC20, PaymasterERC20Guarantor) returns (bool refunded, uint256 actualAmount) {
    return
        super._refund(
            token,
            tokenPrice,
            actualGasCost,
            actualUserOpFeePerGas,
            prefunder,
            prefundAmount,
            prefundContext
        );
}

function _getStructHashWithoutOracleAndGuarantorSignature(
    PackedUserOperation calldata userOp
) private pure returns (bytes32) {
    return
        keccak256(
            abi.encode(
                PACKED_USER_OPERATION_TYPEHASH,
                userOp.sender,
                userOp.nonce,
                keccak256(userOp.initCode),
                keccak256(userOp.callData),
                userOp.accountGasLimits,
                userOp.preVerificationGas,
                userOp.gasFees,
                keccak256(userOp.paymasterAndData[:0x88]) // 0x34 (paymasterDataOffset) + 0x54 (token + validAfter + validUntil + tokenPrice + oracle)
            )
        );
}

function verify(
    bytes calldata key,
    bytes32 hash,
    bytes calldata signature
) public view virtual override returns (bytes4) {
    (IDKIMRegistry registry_, bytes32 accountSalt_, IGroth16Verifier verifier_) = _decodeKey(key);
    (bool decodeSuccess, EmailProof calldata emailProof) = ZKEmailUtils.tryDecodeEmailProof(signature);

    return
        (decodeSuccess &&
            emailProof.accountSalt == accountSalt_ &&
            emailProof.isValidZKEmail(registry_, verifier_, hash) == ZKEmailUtils.EmailProofError.NoError)
            ? IERC7913SignatureVerifier.verify.selector
            : bytes4(0xffffffff);
}

function _propose(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    string memory description,
    address proposer
) internal virtual override returns (uint256) {
    GovernorStorageStorage storage $ = _getGovernorStorageStorage();
    uint256 proposalId = super._propose(targets, values, calldatas, description, proposer);

    // store
    $._proposalIds.push(proposalId);
    $._proposalDetails[proposalId] = ProposalDetails({
        targets: targets,
        values: values,
        calldatas: calldatas,
        descriptionHash: keccak256(bytes(description))
    });

    return proposalId;
}

function proposalExecutionPlan(
    uint256 proposalId
) public view returns (uint32 delay, bool[] memory indirect, bool[] memory withDelay) {
    GovernorTimelockAccessStorage storage $ = _getGovernorTimelockAccessStorage();
    ExecutionPlan storage plan = $._executionPlan[proposalId];

    uint32 length = plan.length;
    delay = plan.delay;
    indirect = new bool[](length);
    withDelay = new bool[](length);
    for (uint256 i = 0; i < length; ++i) {
        (indirect[i], withDelay[i], ) = _getManagerData(plan, i);
    }

    return (delay, indirect, withDelay);
}

function _queueOperations(
    uint256 proposalId,
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 /*descriptionHash*/
) internal virtual override returns (uint48) {
    GovernorTimelockCompoundStorage storage $ = _getGovernorTimelockCompoundStorage();
    uint48 etaSeconds = SafeCast.toUint48(block.timestamp + $._timelock.delay());

    for (uint256 i = 0; i < targets.length; ++i) {
        if (
            $._timelock.queuedTransactions(keccak256(abi.encode(targets[i], values[i], "", calldatas[i], etaSeconds)))
        ) {
            revert GovernorAlreadyQueuedProposal(proposalId);
        }
        $._timelock.queueTransaction(targets[i], values[i], "", calldatas[i], etaSeconds);
    }

    return etaSeconds;
}

function _cancel(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 descriptionHash
) internal virtual override returns (uint256) {
    GovernorTimelockCompoundStorage storage $ = _getGovernorTimelockCompoundStorage();
    uint256 proposalId = super._cancel(targets, values, calldatas, descriptionHash);

    uint256 etaSeconds = proposalEta(proposalId);
    if (etaSeconds > 0) {
        // do external call later
        for (uint256 i = 0; i < targets.length; ++i) {
            $._timelock.cancelTransaction(targets[i], values[i], "", calldatas[i], etaSeconds);
        }
    }

    return proposalId;
}

function _queueOperations(
    uint256 proposalId,
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 descriptionHash
) internal virtual override returns (uint48) {
    GovernorTimelockControlStorage storage $ = _getGovernorTimelockControlStorage();
    uint256 delay = $._timelock.getMinDelay();

    bytes32 salt = _timelockSalt(descriptionHash);
    $._timelockIds[proposalId] = $._timelock.hashOperationBatch(targets, values, calldatas, 0, salt);
    $._timelock.scheduleBatch(targets, values, calldatas, 0, salt, delay);

    return SafeCast.toUint48(block.timestamp + delay);
}

function _cancel(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 descriptionHash
) internal virtual override returns (uint256) {
    GovernorTimelockControlStorage storage $ = _getGovernorTimelockControlStorage();
    uint256 proposalId = super._cancel(targets, values, calldatas, descriptionHash);

    bytes32 timelockId = $._timelockIds[proposalId];
    if (timelockId != 0) {
        // cancel
        $._timelock.cancel(timelockId);
        // cleanup
        delete $._timelockIds[proposalId];
    }

    return proposalId;
}

function royaltyInfo(
    uint256 tokenId,
    uint256 salePrice
) public view virtual returns (address receiver, uint256 amount) {
    ERC2981Storage storage $ = _getERC2981Storage();
    RoyaltyInfo storage _royaltyInfo = $._tokenRoyaltyInfo[tokenId];
    address royaltyReceiver = _royaltyInfo.receiver;
    uint96 royaltyFraction = _royaltyInfo.royaltyFraction;

    if (royaltyReceiver == address(0)) {
        royaltyReceiver = $._defaultRoyaltyInfo.receiver;
        royaltyFraction = $._defaultRoyaltyInfo.royaltyFraction;
    }

    uint256 royaltyAmount = (salePrice * royaltyFraction) / _feeDenominator();

    return (royaltyReceiver, royaltyAmount);
}

function _approve(address to, uint256 tokenId, address auth, bool emitEvent) internal virtual {
    ERC721Storage storage $ = _getERC721Storage();
    // Avoid reading the owner unless necessary
    if (emitEvent || auth != address(0)) {
        address owner = _requireOwned(tokenId);

        // We do not use _isAuthorized because single-token approvals should not be able to call approve
        if (auth != address(0) && owner != auth && !isApprovedForAll(owner, auth)) {
            revert ERC721InvalidApprover(auth);
        }

        if (emitEvent) {
            emit Approval(owner, to, tokenId);
        }
    }

    $._tokenApprovals[tokenId] = to;
}

function _update(address to, uint256 tokenId, address auth) internal virtual override returns (address) {
    ERC721ConsecutiveStorage storage $ = _getERC721ConsecutiveStorage();
    address previousOwner = super._update(to, tokenId, auth);

    // only mint after construction
    if (previousOwner == address(0) && address(this).code.length == 0) {
        revert ERC721ForbiddenMint();
    }

    // record burn
    if (
        to == address(0) && // if we burn
        tokenId < _nextConsecutiveId() && // and the tokenId was minted in a batch
        !$._sequentialBurn.get(tokenId) // and the token was never marked as burnt
    ) {
        $._sequentialBurn.set(tokenId);
    }

    return previousOwner;
}

function _crosschainTransfer(
    address from,
    bytes memory to,
    uint256[] memory ids,
    uint256[] memory values
) internal virtual returns (bytes32) {
    _onSend(from, ids, values);

    (bytes2 chainType, bytes memory chainReference, bytes memory addr) = to.parseV1();
    bytes memory chain = InteroperableAddress.formatV1(chainType, chainReference, hex"");

    bytes32 sendId = _sendMessageToCounterpart(
        chain,
        abi.encode(InteroperableAddress.formatEvmV1(block.chainid, from), addr, ids, values),
        new bytes[](0)
    );

    emit CrosschainMultiTokenTransferSent(sendId, from, to, ids, values);
    return sendId;
}

function _processMessage(
    address /*gateway*/,
    bytes32 receiveId,
    bytes calldata /*sender*/,
    bytes calldata payload
) internal virtual override {
    // NOTE: Gateway is validated by {_isAuthorizedGateway} (implemented in {CrosschainLinked}). No need to check here.

    // split payload
    (bytes memory from, bytes memory toEvm, uint256[] memory ids, uint256[] memory values) = abi.decode(
        payload,
        (bytes, bytes, uint256[], uint256[])
    );
    address to = address(bytes20(toEvm));

    _onReceive(to, ids, values);

    emit CrosschainMultiTokenTransferReceived(receiveId, from, to, ids, values);
}

function _crosschainTransfer(address from, bytes memory to, uint256 tokenId) internal virtual returns (bytes32) {
    _onSend(from, tokenId);

    (bytes2 chainType, bytes memory chainReference, bytes memory addr) = InteroperableAddress.parseV1(to);
    bytes memory chain = InteroperableAddress.formatV1(chainType, chainReference, hex"");

    bytes32 sendId = _sendMessageToCounterpart(
        chain,
        abi.encode(InteroperableAddress.formatEvmV1(block.chainid, from), addr, tokenId),
        new bytes[](0)
    );

    emit CrosschainNonFungibleTransferSent(sendId, from, to, tokenId);

    return sendId;
}

function _processMessage(
    address /*gateway*/,
    bytes32 /*receiveId*/,
    bytes calldata /*sender*/,
    bytes calldata payload
) internal virtual override {
    // split payload
    (CallType callType, ExecType execType, , ) = Mode.wrap(bytes32(payload[0x00:0x20])).decodeMode();
    bytes calldata executionCalldata = payload[0x20:];

    if (callType == ERC7579Utils.CALLTYPE_SINGLE) {
        executionCalldata.execSingle(execType);
    } else if (callType == ERC7579Utils.CALLTYPE_BATCH) {
        executionCalldata.execBatch(execType);
    } else if (callType == ERC7579Utils.CALLTYPE_DELEGATECALL) {
        executionCalldata.execDelegateCall(execType);
    } else revert ERC7579Utils.ERC7579UnsupportedCallType(callType);
}

function castOverrideVoteBySig(
    uint256 proposalId,
    uint8 support,
    address voter,
    string calldata reason,
    bytes calldata signature
) public virtual returns (uint256) {
    bool valid = SignatureChecker.isValidSignatureNow(
        voter,
        _hashTypedDataV4(
            keccak256(
                abi.encode(
                    OVERRIDE_BALLOT_TYPEHASH,
                    proposalId,
                    support,
                    voter,
                    _useNonce(voter),
                    keccak256(bytes(reason))
                )
            )
        ),
        signature
    );

    if (!valid) {
        revert GovernorInvalidSignature(voter);
    }

    return _castOverride(proposalId, voter, support, reason);
}

function _validateVoteSig(
    uint256 proposalId,
    uint8 support,
    address voter,
    bytes memory signature
) internal virtual override returns (bool) {
    if (
        SignatureChecker.isValidSignatureNow(
            voter,
            _hashTypedDataV4(
                keccak256(
                    abi.encode(BALLOT_TYPEHASH, proposalId, support, voter, nonces(voter, uint192(proposalId)))
                )
            ),
            signature
        )
    ) {
        _useNonce(voter, uint192(proposalId));
        return true;
    } else {
        return super._validateVoteSig(proposalId, support, voter, signature);
    }
}

